data.value:
decimal sumWeightedProdValues = 0;  // Σ(TotalProd × FemaleBalance)
decimal sumWeights = 0;            // Σ(FemaleBalance)
decimal sumWeightedHatEggValues = 0;  // Σ(TotalHatEgg × TotalProd)
decimal sumWeightedHatEggValuesReport = 0;  // Σ(TotalHatEgg × TotalProd)
decimal sumWeightsHatEggReport = 0;              // Σ(TotalProd)
decimal TotalFemaleBalanceGroup  = 0;
decimal TotalMaleBalanceGroup = 0;
decimal sumFeedPer1000 = 0;
int countFeedPer1000 = 0;
decimal sumMaleFeedPer1000 = 0;
decimal countMaleFeedPer1000 = 0;
decimal sumStockToHatEggRatio = 0;
int countStockToHatEggRatio = 0;
decimal sumFemaleDeplPercent = 0;
int countFemaleDeplPercent = 0;
decimal sumMaleDeplPercent = 0;
int countMaleDeplPercent = 0;
private void xrTableCell101_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get values from fields
    decimal femaleBalance = Convert.ToDecimal(GetCurrentColumnValue("FemaleBalance") ?? 0);
    decimal totalProd = Convert.ToDecimal(GetCurrentColumnValue("TotalProd") ?? 0);

    // Calculate: (TotalProd / FemaleBalance) * 100
    if (femaleBalance > 0 && totalProd > 0) {
        decimal result = (totalProd / femaleBalance) * 100;
        cell.Text = result.ToString("N0"); // 1 decimal place with %
        // Or: result.ToString("F1") without %
    } else {
        cell.Text = "0"; // or "0"
    }
}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     // Get values from fields
    decimal femaleBalance = Convert.ToDecimal(GetCurrentColumnValue("FemaleBalance") ?? 0);
    decimal totalProd = Convert.ToDecimal(GetCurrentColumnValue("TotalProd") ?? 0);

    // Only accumulate if both values are positive
    if (femaleBalance > 0 && totalProd > 0) {
        // For weighted average: (TotalProd × FemaleBalance)
        // This gives more weight to rows with more birds
        sumWeightedProdValues += (totalProd * femaleBalance);
        sumWeights += femaleBalance;
    }

        // Get values from fields
    decimal totalHatEgg = Convert.ToDecimal(GetCurrentColumnValue("TotalHatEgg") ?? 0);

    // Only accumulate if both values are positive
    if (totalProd > 0 && totalHatEgg > 0) {
        // Weighted value: TotalHatEgg × TotalProd
        sumWeightedHatEggValues += (totalHatEgg * totalProd);
        sumWeights += totalProd;
    }


    // Get values from fields
    decimal maleBalance = Convert.ToDecimal(GetCurrentColumnValue("MaleBalance") ?? 0);
    TotalFemaleBalanceGroup += femaleBalance ;
    TotalMaleBalanceGroup += maleBalance ;

    decimal femaleFeedCons = Convert.ToDecimal(GetCurrentColumnValue("FemaleFeedCons") ?? 0);

    if (femaleBalance > 0) {
        decimal feedPer1000 = (femaleFeedCons * 1000) / femaleBalance;
        sumFeedPer1000 += feedPer1000;
        countFeedPer1000++;
    }
    decimal maleFeedCons = Convert.ToDecimal(GetCurrentColumnValue("MaleFeedCons") ?? 0);

    if (maleBalance > 0) {
        decimal feedPer1000 = (maleFeedCons * 1000) / maleBalance;
        sumMaleFeedPer1000 += feedPer1000;
        countMaleFeedPer1000++;
    }

    decimal eggStock = Convert.ToDecimal(GetCurrentColumnValue("EggStock") ?? 0);

    if (totalHatEgg > 0) {
        decimal ratio = eggStock / totalHatEgg;
        sumStockToHatEggRatio += ratio;
        countStockToHatEggRatio++;
    }

     decimal femaleDepl = Convert.ToDecimal(GetCurrentColumnValue("FemaleDepl") ?? 0);

    if (femaleBalance > 0) {
        decimal percent = (femaleDepl * 100) / femaleBalance;
        sumFemaleDeplPercent += percent;
        countFemaleDeplPercent++;
    }

    decimal maleDepl = Convert.ToDecimal(GetCurrentColumnValue("MaleDepl") ?? 0);

    if (maleBalance > 0) {
        decimal percent = (maleDepl * 100) / maleBalance;
        sumMaleDeplPercent += percent;
        countMaleDeplPercent++;
    }
}

private void xrTableCell15_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Calculate weighted average: Σ(TotalProd×FemaleBalance) / Σ(FemaleBalance) × 100
    if (sumWeights > 0) {
        decimal weightedAvg = (sumWeightedProdValues / sumWeights) * 100;
        cell.Text = weightedAvg.ToString("N2") ; // 1 decimal place
    } else {
        cell.Text = "0.00";
    }
}

