private void xrTableCell43_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {  
     XRTableCell cell = sender as XRTableCell;
     decimal totalProd = Convert.ToDecimal(GetCurrentColumnValue("TotalProd") ?? 0);
    decimal totalHatEgg = Convert.ToDecimal(GetCurrentColumnValue("TotalHatEgg") ?? 0);

    // Only accumulate if both values are positive
    if (totalProd > 0 && totalHatEgg > 0) {
        // Weighted value: TotalHatEgg × TotalProd
        sumWeightedHatEggValuesReport += (totalHatEgg * totalProd);
        sumWeightsHatEggReport += totalProd;
    }
     // Calculate weighted average: Σ(TotalHatEgg×TotalProd) / Σ(TotalProd) × 100
    if (sumWeightsHatEggReport > 0) {
        decimal weightedAvg = (sumWeightedHatEggValuesReport / sumWeightsHatEggReport ) * 100;
        cell.Text = weightedAvg.ToString("N2"); // 1 decimal place
    } else {
        cell.Text = "0.00";
    }

}

